-- Prompt 17 rotating tokens, replay prevention, manual fallback, guest events and RLS.
begin;
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);select public.configure_day_pass_registration('30000000-0000-4000-8000-000000000001',true,16,'Test');
do $$ declare version_id uuid;begin version_id:=public.save_waiver_draft('30000000-0000-4000-8000-000000000001',null,'Check-in waiver','',true,'Check-in waiver','Check-in test text','{"collect_date_of_birth":false,"require_age_confirmation":true,"minimum_age":18,"collect_emergency_contact":false,"consent_items":["I accept"]}'::jsonb);perform public.publish_waiver_version('30000000-0000-4000-8000-000000000001',version_id);perform public.accept_member_waiver('30000000-0000-4000-8000-000000000001',version_id,'{"accepted_name":"Demo Owner","signature_text":"Demo Owner","date_of_birth":"","age_confirmed":true,"emergency_contact_name":"","emergency_contact_phone":"","consents":["I accept"]}'::jsonb);end;$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
do $$ declare version_id uuid;begin select id into version_id from public.waiver_versions where title='Check-in waiver';perform public.accept_member_waiver('30000000-0000-4000-8000-000000000001',version_id,'{"accepted_name":"Demo Member","signature_text":"Demo Member","date_of_birth":"","age_confirmed":true,"emergency_contact_name":"","emergency_contact_phone":"","consents":["I accept"]}'::jsonb);perform public.issue_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('a',64),now()+interval '2 minutes');perform public.issue_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('b',64),now()+interval '2 minutes');end;$$;
set local role service_role;insert into public.check_in_tokens(gym_id,profile_id,token_hash,created_at,expires_at)values('30000000-0000-4000-8000-000000000001','10000000-0000-4000-8000-000000000004',repeat('e',64),now()-interval '2 minutes',now()-interval '1 minute');
select public.register_public_day_pass('demo-crux-centre','Wallet Guest','',repeat('c',64),repeat('d',64),'integration_placeholder');
do $$ declare version_id uuid;begin select id into version_id from public.waiver_versions where title='Check-in waiver';perform public.accept_guest_waiver(repeat('c',64),version_id,'{"accepted_name":"Wallet Guest","signature_text":"Wallet Guest","date_of_birth":"","age_confirmed":true,"emergency_contact_name":"","emergency_contact_phone":"","consents":["I accept"]}'::jsonb);end;$$;
set local role authenticated;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000002',true);
do $$ declare result jsonb; member_check_in uuid; owner_membership uuid;begin result:=public.verify_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('a',64));if result->>'token_status'<>'revoked' then raise exception 'Rotated token was not revoked';end if;result:=public.verify_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('b',64));if result->>'token_status'<>'valid' or result->>'member_name'<>'Demo Member' or (result->>'waivers_complete')::boolean is not true then raise exception 'Valid member token did not verify';end if;member_check_in:=public.check_in_member_token('30000000-0000-4000-8000-000000000001',repeat('b',64));begin perform public.check_in_member_token('30000000-0000-4000-8000-000000000001',repeat('b',64));raise exception 'Consumed member token replayed';exception when raise_exception then null;end;result:=public.verify_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('e',64));if result->>'token_status'<>'expired' then raise exception 'Expired token did not fail clearly';end if;select id into owner_membership from public.gym_memberships where gym_id='30000000-0000-4000-8000-000000000001' and profile_id='10000000-0000-4000-8000-000000000001';perform public.manual_member_check_in('30000000-0000-4000-8000-000000000001',owner_membership);perform public.check_in_guest_pass('30000000-0000-4000-8000-000000000001',repeat('d',64),false);if not exists(select 1 from public.check_ins where id=member_check_in and gym_id='30000000-0000-4000-8000-000000000001' and source='member_qr') then raise exception 'Member check-in event missing';end if;end;$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);do $$begin if exists(select 1 from public.check_ins where profile_id is distinct from auth.uid()) then raise exception 'Member saw another subject check-in';end if;begin perform public.verify_member_check_in_token('30000000-0000-4000-8000-000000000001',repeat('b',64));raise exception 'Member used front-desk verification';exception when insufficient_privilege then null;end;end;$$;
set local role service_role;do $$begin if not exists(select 1 from public.check_ins where source='manual') or not exists(select 1 from public.check_ins where source='guest_pass') then raise exception 'Manual or guest check-in event missing';end if;if not exists(select 1 from public.audit_logs where action='member.checked_in') then raise exception 'Member check-in audit missing';end if;end;$$;
rollback;
